import{_ as t,c as a,o as r,a1 as o}from"./chunks/framework.9hXSu8bi.js";const l="/mypatterndocs/static/%E4%B8%89%E7%BB%B4%E9%A1%B5%E9%9D%A2%E4%BB%8B%E7%BB%8D.Bv5gFRcv.png",f=JSON.parse('{"title":"","description":"","frontmatter":{"title":"","description":"","navbar":true,"sideBar":true,"footer":false,"outline":[1,3],"editLink":false,"lastUpdated":true,"aside":"right","layout":"doc","custom":{},"hero":{"image":{"src":"","alt":"","width":"","height":""},"name":"方向图文档发布系统","text":"quick to config vitePress","description":"","tagline":"","actions":[],"features":[],"head":[]}},"headers":[],"relativePath":"zh/帮助文档/功能介绍/三维页面.md","filePath":"zh/帮助文档/功能介绍/三维页面.md"}'),i={name:"zh/帮助文档/功能介绍/三维页面.md"},e=o('<h1 id="三维页面" tabindex="-1">三维页面 <a class="header-anchor" href="#三维页面" aria-label="Permalink to &quot;三维页面&quot;">​</a></h1><blockquote><p>三维页面是平台的监测核心，提供三维地形可视化、监测数据叠加、形变分析等专业功能，支持从任意角度查看监测项目。</p></blockquote><p><img src="'+l+'" alt="" data-fancybox="gallery"></p><h3 id="_1-子项目信息" tabindex="-1">1. 子项目信息 <a class="header-anchor" href="#_1-子项目信息" aria-label="Permalink to &quot;1. 子项目信息&quot;">​</a></h3><ul><li><strong>子项目名称</strong>：显示当前选中的子项目名称。</li><li><strong>最新数据时间</strong>：展示当前子项目最新的监测数据的采集时间。</li><li><strong>地图名称</strong>：当前加载的地形数据名称，通常为上传的TIFF文件。</li><li><strong>拍摄日期</strong>：地形数据或影像的拍摄日期。</li><li><strong>地图数据类型</strong>：当前地形数据的格式类型，如TIFF、OSGB、DXF等。</li><li><strong>位移视图-查看模式</strong>：切换形变数据的显示方式，共六种，如位移视图-图像预警模式、速度视图-曲线预警模式等，可在视图功能界面进行修改。</li></ul><h3 id="_2-地图相关" tabindex="-1">2. 地图相关 <a class="header-anchor" href="#_2-地图相关" aria-label="Permalink to &quot;2. 地图相关&quot;">​</a></h3><ul><li><strong>地图</strong>：显示当前项目的所处位置。</li><li><strong>监测点/面</strong>：用户手动添加的监测点/面，点击监测点/面的图标可查看形变曲线。</li><li><strong>雷达图标</strong>：显示雷达设备在地图上的位置。</li></ul><h3 id="_3-显示设置" tabindex="-1">3. 显示设置 <a class="header-anchor" href="#_3-显示设置" aria-label="Permalink to &quot;3. 显示设置&quot;">​</a></h3><ul><li><strong>设置</strong>：对图例进行配置，如增删颜色条、图例复制等功能。</li><li><strong>颜色条</strong>：不同的颜色条区间反映不同的形变值。</li></ul><h3 id="_4-标记信息" tabindex="-1">4. 标记信息 <a class="header-anchor" href="#_4-标记信息" aria-label="Permalink to &quot;4. 标记信息&quot;">​</a></h3><ul><li><strong>编号</strong>：当前选中监测点或监测面的唯一标识编号。</li><li><strong>备注</strong>：用户为监测点或监测面添加的自定义备注信息，便于识别和管理。</li></ul><h3 id="_5-工具栏" tabindex="-1">5. 工具栏 <a class="header-anchor" href="#_5-工具栏" aria-label="Permalink to &quot;5. 工具栏&quot;">​</a></h3><ul><li><strong>图层</strong>：打开图层管理面板，可以切换图像类别、地图类别、地形类别以及控制子项目的不同图层的显隐。</li><li><strong>视图</strong>：支持切换三维场景的视图模式，对历史数据进行查询等功能。</li><li><strong>工具</strong>：用户在此页面可以手动添加监测点、监测面等，同时可以使用测量工具和关联分析功能。</li><li><strong>报告</strong>：快速生成当前子项目的监测报告或监测数据，支持预览和导出（时间间隔可按小时、天、月）。</li><li><strong>系统</strong>：管理监测数据（例如对监测点/面进行编辑、删除或定位）、视角书签和天空底色。</li></ul><h3 id="_6-坐标信息" tabindex="-1">6. 坐标信息 <a class="header-anchor" href="#_6-坐标信息" aria-label="Permalink to &quot;6. 坐标信息&quot;">​</a></h3><ul><li><strong>纬度</strong>：显示当前鼠标位置选中点的纬度坐标。</li><li><strong>经度</strong>：显示当前鼠标位置选中点的经度坐标。</li><li><strong>高程</strong>：显示当前鼠标位置选中点的高程值。</li></ul><h3 id="_7-视图导航" tabindex="-1">7. 视图导航 <a class="header-anchor" href="#_7-视图导航" aria-label="Permalink to &quot;7. 视图导航&quot;">​</a></h3><ul><li><strong>旋转地图</strong>：按住并拖拽可自由旋转三维场景，从不同角度观察监测项目。</li><li><strong>放大</strong>：点击可放大地图视图，更清晰地查看局部细节。</li><li><strong>房子</strong>：点击后快速恢复到默认视角和位置，便于重新定位。</li><li><strong>缩小</strong>：点击可缩小地图视图，查看更大范围的场景。</li></ul>',17),n=[e];function s(g,h,c,d,_,u){return r(),a("div",null,n)}const p=t(i,[["render",s]]);export{f as __pageData,p as default};
